import React, { createContext, useContext, useState, useEffect } from 'react';
import api from '../api/axiosInstance';
import type { Mess } from '../types/mess';
import { useAppSelector } from '../../hooks/redux';
import type { RootState } from '../../store';

interface FavoritesContextType {
    favorites: string[];
    toggleFavorite: (messId: string) => Promise<boolean>;
    isFavorite: (messId: string) => boolean;
    loading: boolean;
}

const FavoritesContext = createContext<FavoritesContextType | undefined>(undefined);

export const FavoritesProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [favorites, setFavorites] = useState<string[]>([]);
    const [loading, setLoading] = useState(false);
    const { token, user } = useAppSelector((state: RootState) => state.auth);

    useEffect(() => {
        const fetchFavorites = async () => {
            if (!token || !user) { // Check for user as well
                setFavorites([]);
                return;
            }
            setLoading(true);
            try {
                const response = await api.get('/favorites');
                if (response.data.success) {
                    const ids = response.data.data.map((m: Mess) => String(m.id)); // Use Mess type
                    setFavorites(ids);
                }
            } catch (error) {
                console.error('Error fetching favorites:', error);
            } finally {
                setLoading(false);
            }
        };

        fetchFavorites();
    }, [token, user]);

    const toggleFavorite = async (messId: string) => {
        const id = String(messId);

        if (!token) {
            alert('Please login to favorite messes!');
            window.location.href = '/login';
            return false;
        }

        // Optimistic update
        const wasFavorite = favorites.includes(id);
        if (wasFavorite) {
            setFavorites(prev => prev.filter(fid => fid !== id));
        } else {
            setFavorites(prev => [...prev, id]);
        }

        try {
            const response = await api.post(`/favorites/toggle/${id}`);
            if (response.data.success) {
                // Keep the sync with server just in case
                if (response.data.isFavorite) {
                    setFavorites(prev => prev.includes(id) ? prev : [...prev, id]);
                } else {
                    setFavorites(prev => prev.filter(fid => fid !== id));
                }
                return response.data.isFavorite;
            }
        } catch (error) {
            // Revert on error
            if (wasFavorite) {
                setFavorites(prev => prev.includes(id) ? prev : [...prev, id]);
            } else {
                setFavorites(prev => prev.filter(fid => fid !== id));
            }
            console.error('Error toggling favorite:', error);
            alert('Could not update favorite. Please check your connection.');
        }
        return false;
    };

    const isFavorite = (messId: string | undefined) => {
        if (!messId) return false;
        return favorites.includes(String(messId));
    };

    return (
        <FavoritesContext.Provider value={{ favorites, toggleFavorite, isFavorite, loading }}>
            {children}
        </FavoritesContext.Provider>
    );
};

export const useFavorites = () => {
    const context = useContext(FavoritesContext);
    if (context === undefined) {
        throw new Error('useFavorites must be used within a FavoritesProvider');
    }
    return context;
};

import React, { useState, useEffect } from 'react';
import { Layout } from '../components/layout/Layout';
import { Card } from '../components/common/Card';
import { Button } from '../components/common/Button';
import {
    LayoutDashboard,
    Utensils,
    Users,
    TrendingUp,
    Settings,
    Save,
    Trash2,
    CircleCheck,
    MapPin,
    Phone,
    Image as ImageIcon,
    Clock,
    CreditCard,
    Calendar
} from 'lucide-react';
import { useAppSelector } from '../../hooks/redux';
import type { RootState } from '../../store';
import api from '../api/axiosInstance';
import { toast } from 'react-hot-toast';
import { BillingHistoryModal } from '../components/dashboard/BillingHistoryModal';
import { useNavigate } from 'react-router-dom';
import type { Mess, Subscription, Menu, MenuItem } from '../types/mess';

type Tab = 'overview' | 'menu' | 'subscribers' | 'settings';

const OwnerDashboardPage: React.FC = () => {
    const navigate = useNavigate();
    const { user } = useAppSelector((state: RootState) => state.auth);
    const [activeTab, setActiveTab] = useState<Tab>('overview');
    const [mess, setMess] = useState<Mess | null>(null);
    const [subscribers, setSubscribers] = useState<Subscription[]>([]);
    const [menus, setMenus] = useState<Menu[]>([]);
    const [revenue, setRevenue] = useState<number>(0);
    const [loading, setLoading] = useState(true);
    const [updating, setUpdating] = useState(false);
    const [savingMenu, setSavingMenu] = useState(false);
    const [selectedDay, setSelectedDay] = useState('Monday');
    const [isBillingModalOpen, setIsBillingModalOpen] = useState(false);
    const [subscription, setSubscription] = useState<Subscription | null>(null);


    // Form states
    const [messForm, setMessForm] = useState({
        name: '',
        description: '',
        address: '',
        cuisine: '',
        contact: '',
        images: [] as string[]
    });

    useEffect(() => {
        const fetchOwnerData = async () => {
            try {
                setLoading(true);
                const [messRes, subsRes, subStatusRes] = await Promise.all([
                    api.get('/messes/my'),
                    api.get('/subscriptions/subscribers'),
                    api.get('/subscriptions/status')
                ]);

                setMess(messRes.data.data);
                setMenus(messRes.data.data.menus || []);
                setSubscribers(subsRes.data.data);
                setRevenue(subsRes.data.totalRevenue || 0);
                setSubscription(subStatusRes.data.data);
                setMessForm({
                    name: messRes.data.data?.name || '',
                    description: messRes.data.data?.description || '',
                    address: messRes.data.data?.address || '',
                    cuisine: messRes.data.data?.cuisine || '',
                    contact: messRes.data.data?.contact || '',
                    images: messRes.data.data?.images || []
                });
            } catch (error) {
                console.error('Error fetching owner data:', error);
                toast.error('Failed to load dashboard data');
            } finally {
                setLoading(false);
            }
        };

        if (user && user.role === 'OWNER') fetchOwnerData();

        // Load Razorpay Script
        const script = document.createElement('script');
        script.src = 'https://checkout.razorpay.com/v1/checkout.js';
        script.async = true;
        document.body.appendChild(script);

        return () => {
            document.body.removeChild(script);
        };
    }, [user]);

    const handleUpdateMess = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            setUpdating(true);
            const response = await api.put('/messes/my', messForm);
            setMess(response.data.data);
            toast.success('Mess profile updated successfully');
        } catch (error) {
            toast.error('Failed to update mess profile');
        } finally {
            setUpdating(false);
        }
    };

    const handleMenuSave = async () => {
        try {
            setSavingMenu(true);
            await api.put('/messes/my/menu', { menus });
            toast.success('Weekly menu updated successfully!');
        } catch (error) {
            console.error('Error saving menu:', error);
            toast.error('Failed to save menu.');
        } finally {
            setSavingMenu(false);
        }
    };

    const handleItemChange = (day: string, itemIndex: number, field: string, value: string) => {
        setMenus(prevMenus => {
            const newMenus = [...prevMenus];
            const dayMenuIndex = newMenus.findIndex(m => m.day === day);

            if (dayMenuIndex !== -1) {
                const newItems = [...newMenus[dayMenuIndex].items];
                newItems[itemIndex] = { ...newItems[itemIndex], [field]: value };
                newMenus[dayMenuIndex] = { ...newMenus[dayMenuIndex], items: newItems };
            } else {
                // If day doesn't exist, create it and add the item
                newMenus.push({
                    day,
                    items: [{ name: '', type: 'Veg', [field]: value }]
                });
            }
            return newMenus;
        });
    };

    const handleAddItem = (day: string) => {
        setMenus(prevMenus => {
            const newMenus = [...prevMenus];
            const dayMenuIndex = newMenus.findIndex(m => m.day === day);

            if (dayMenuIndex !== -1) {
                newMenus[dayMenuIndex] = {
                    ...newMenus[dayMenuIndex],
                    items: [...newMenus[dayMenuIndex].items, { name: '', type: 'Veg' }]
                };
            } else {
                newMenus.push({
                    day,
                    items: [{ name: '', type: 'Veg' }]
                });
            }
            return newMenus;
        });
    };

    const handleRemoveItem = (day: string, itemIndex: number) => {
        setMenus(prevMenus => {
            const newMenus = [...prevMenus];
            const dayMenuIndex = newMenus.findIndex(m => m.day === day);

            if (dayMenuIndex !== -1) {
                const newItems = newMenus[dayMenuIndex].items.filter((_: MenuItem, idx: number) => idx !== itemIndex);
                newMenus[dayMenuIndex] = { ...newMenus[dayMenuIndex], items: newItems };
            }
            return newMenus;
        });
    };


    const renderOverview = () => (
        <div className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {[
                    { label: 'Total Revenue', value: `Γé╣${revenue.toLocaleString()}`, trend: '+12%', icon: <TrendingUp className="text-secondary" /> },
                    { label: 'Active Subscribers', value: subscribers.length.toString(), trend: '+5', icon: <Users className="text-primary" /> },
                    { label: 'Avg Rating', value: mess?.rating?.toFixed(1) || '0.0', trend: 'Global', icon: <Utensils className="text-accent" /> },
                ].map((stat, i) => (
                    <Card key={i} className="p-6">
                        <div className="flex justify-between items-start mb-4">
                            <div className="p-3 bg-gray-50 rounded-xl">{stat.icon}</div>
                            <span className={`text-xs font-bold px-2 py-1 rounded-full ${stat.trend.startsWith('+') ? 'bg-green-100 text-green-600' : 'bg-gray-100 text-gray-500'}`}>
                                {stat.trend}
                            </span>
                        </div>
                        <p className="text-gray-400 text-sm font-medium">{stat.label}</p>
                        <p className="text-3xl font-black mt-1">{stat.value}</p>
                    </Card>
                ))}
            </div>

            {/* Subscription Status Card */}
            <section className="space-y-4">
                <h2 className="text-xl font-bold">Subscription Status</h2>
                <Card className="p-6 overflow-hidden border-2 border-primary/20 bg-primary/5">
                    <div className="flex flex-col md:flex-row items-center justify-between gap-6">
                        <div className="flex items-center space-x-6">
                            <div className={`p-4 rounded-2xl ${subscription?.status === 'trial' ? 'bg-orange-100 text-orange-600' :
                                subscription?.status === 'active' ? 'bg-green-100 text-green-600' :
                                    'bg-red-100 text-red-600'
                                }`}>
                                <CreditCard size={32} />
                            </div>
                            <div>
                                <div className="flex items-center space-x-3 mb-1">
                                    <h3 className="text-lg font-black uppercase tracking-tight">
                                        {subscription?.status === 'trial' ? '60-Day Free Trial' : 'Elite Listing Plan'}
                                    </h3>
                                    <span className={`text-[10px] font-black px-2 py-1 rounded-lg uppercase ${subscription?.status === 'trial' ? 'bg-orange-500 text-white' :
                                        subscription?.status === 'active' ? 'bg-green-500 text-white' :
                                            'bg-red-500 text-white'
                                        }`}>
                                        {subscription?.status || 'No Plan'}
                                    </span>
                                </div>
                                <div className="flex items-center space-x-4 text-sm font-bold text-gray-500">
                                    {subscription?.status === 'trial' && (
                                        <div className="flex items-center text-orange-600">
                                            <Clock size={16} className="mr-1" />
                                            <span>
                                                {(() => {
                                                    if (!subscription?.trial_end) return '60 days remaining';
                                                    const end = new Date(subscription.trial_end);
                                                    const now = new Date();
                                                    const diff = Math.ceil((end.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
                                                    return `${Math.max(0, diff)} days remaining`;
                                                })()}
                                            </span>
                                        </div>
                                    )}
                                    {subscription?.subscription_end && (
                                        <div className="flex items-center">
                                            <Calendar size={16} className="mr-1" />
                                            <span>Next billing: {new Date(subscription.subscription_end).toLocaleDateString()}</span>
                                        </div>
                                    )}
                                    <div className="flex items-center">
                                        <CircleCheck size={16} className="mr-1 text-green-500" />
                                        <span>Status: {subscription?.status?.toUpperCase() || 'INACTIVE'}</span>
                                    </div>
                                </div>
                            </div>
                        </div>
                        <div className="flex space-x-3">
                            {subscription?.status !== 'active' && (
                                <>
                                    <Button
                                        className="rounded-xl px-8 shadow-lg shadow-primary/20"
                                        onClick={() => navigate('/owner/subscribe')}
                                        isLoading={updating}
                                    >
                                        Subscribe (Γé╣499/mo)
                                    </Button>
                                </>
                            )}
                            <Button
                                variant="outline"
                                className="rounded-xl border-gray-200"
                                onClick={() => setIsBillingModalOpen(true)}
                            >
                                Billing History
                            </Button>
                        </div>
                    </div>
                </Card>
            </section>

            <section className="space-y-4">
                <h2 className="text-xl font-bold">Quick Activity</h2>
                <Card className="p-0 overflow-hidden">
                    <div className="divide-y divide-gray-100">
                        {subscribers.slice(0, 5).map(sub => (
                            <div key={sub.id} className="p-4 flex items-center justify-between hover:bg-gray-50 transition-colors">
                                <div className="flex items-center space-x-3">
                                    <div className="w-10 h-10 rounded-full bg-primary/10 flex items-center justify-center text-primary font-bold">
                                        {sub.user?.name.charAt(0) || '?'}
                                    </div>
                                    <div>
                                        <p className="font-bold text-sm">{sub.user?.name || 'Unknown Student'}</p>
                                        <p className="text-xs text-gray-400">{sub.plan_type} Plan ΓÇó {sub.created_at ? new Date(sub.created_at).toLocaleDateString() : 'N/A'}</p>
                                    </div>
                                </div>
                                <span className="text-[10px] font-black uppercase text-green-500 bg-green-50 px-2 py-1 rounded-lg">Active</span>
                            </div>
                        ))}
                    </div>
                </Card>
            </section>
        </div>
    );

    const renderMenuManagement = () => (
        <div className="space-y-6">
            <div className="flex justify-between items-center mb-10">
                <div className="space-y-1">
                    <h2 className="text-3xl font-black text-dark-900">Menu Schedule</h2>
                    <p className="text-gray-500 text-sm font-medium uppercase tracking-widest">Manage your weekly specials</p>
                </div>
                <Button
                    onClick={handleMenuSave}
                    isLoading={savingMenu}
                    className="bg-primary hover:bg-primary/90 px-10 py-6 rounded-2xl font-black uppercase tracking-widest"
                >
                    Save Weekly Menu
                </Button>
            </div>

            <div className="flex gap-3 overflow-x-auto pb-6 mb-10 scrollbar-hide">
                {['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'].map((day) => (
                    <button
                        key={day}
                        onClick={() => setSelectedDay(day)}
                        className={`px-8 py-4 rounded-2xl text-xs font-black uppercase tracking-widest transition-all whitespace-nowrap border-2 ${selectedDay === day
                            ? 'bg-primary text-white border-primary shadow-[0_0_30px_rgba(255,69,0,0.2)]'
                            : 'bg-gray-50 text-gray-500 border-transparent hover:bg-gray-100 hover:text-gray-700'
                            }`}
                    >
                        {day}
                    </button>
                ))}
            </div>

            <div className="space-y-6">
                {menus.find(m => m.day === selectedDay)?.items.map((item: MenuItem, idx: number) => (
                    <div key={idx} className="bg-white p-8 rounded-3xl flex flex-col md:flex-row gap-6 items-center group transition-all hover:bg-gray-50 relative border border-gray-100">
                        <div className="flex-1 w-full space-y-3">
                            <label className="text-[10px] font-black uppercase tracking-widest text-gray-400">Item Name</label>
                            <input
                                type="text"
                                value={item.name}
                                onChange={(e) => handleItemChange(selectedDay, idx, 'name', e.target.value)}
                                className="w-full bg-gray-50 border border-gray-100 p-6 rounded-2xl text-dark-900 outline-none focus:ring-2 focus:ring-primary transition-all"
                                placeholder="Enter item name..."
                            />
                        </div>
                        <div className="w-full md:w-64 space-y-3">
                            <label className="text-[10px] font-black uppercase tracking-widest text-gray-400">Category</label>
                            <select
                                value={item.type}
                                onChange={(e) => handleItemChange(selectedDay, idx, 'type', e.target.value)}
                                className="w-full bg-gray-50 border border-gray-100 p-6 rounded-2xl text-dark-900 outline-none focus:ring-2 focus:ring-primary transition-all appearance-none"
                            >
                                <option value="Veg" className="bg-white">Veg</option>
                                <option value="Non-Veg" className="bg-white">Non-Veg</option>
                            </select>
                        </div>
                        <div className="pt-6 md:pt-8 w-full md:w-auto">
                            <button
                                onClick={() => handleRemoveItem(selectedDay, idx)}
                                className="w-full md:w-auto p-6 bg-red-500/10 text-red-500 rounded-2xl hover:bg-red-500 hover:text-white transition-all border border-red-500/20"
                            >
                                Remove
                            </button>
                        </div>
                    </div>
                ))}

                <button
                    onClick={() => handleAddItem(selectedDay)}
                    className="w-full border-2 border-dashed border-gray-200 p-10 rounded-3xl text-sm font-black uppercase tracking-widest text-gray-400 hover:border-primary hover:text-primary hover:bg-primary/5 transition-all group"
                >
                    <span className="group-hover:scale-110 transition-transform inline-block">+ Add Item to {selectedDay}</span>
                </button>
            </div>
        </div>
    );

    const renderSubscribers = () => (
        <div className="space-y-6">
            <h2 className="text-xl font-bold">Active Subscribers ({subscribers.length})</h2>
            <Card className="p-0 overflow-hidden">
                <table className="w-full text-left">
                    <thead className="bg-gray-50 border-b border-gray-100">
                        <tr>
                            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase">Student</th>
                            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase">Plan</th>
                            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase">Started</th>
                            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase">Status</th>
                            <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {subscribers.map(sub => (
                            <tr key={sub.id} className="hover:bg-gray-50 transition-colors">
                                <td className="px-6 py-4">
                                    <div className="flex items-center space-x-3">
                                        <div className="w-8 h-8 rounded-full bg-gray-200" />
                                        <div>
                                            <p className="font-bold text-sm">{sub.user?.name || 'Unknown'}</p>
                                            <p className="text-xs text-gray-400">{sub.user?.email || 'N/A'}</p>
                                        </div>
                                    </div>
                                </td>
                                <td className="px-6 py-4">
                                    <p className="text-sm font-medium">{sub.plan_type}</p>
                                </td>
                                <td className="px-6 py-4 text-sm text-gray-500">
                                    {sub.created_at ? new Date(sub.created_at).toLocaleDateString() : 'N/A'}
                                </td>
                                <td className="px-6 py-4">
                                    <span className="text-[10px] font-bold px-2 py-1 bg-green-100 text-green-600 rounded-lg uppercase">Active</span>
                                </td>
                                <td className="px-6 py-4">
                                    <Button variant="ghost" size="sm" className="text-red-500 hover:bg-red-50">
                                        <Trash2 size={16} />
                                    </Button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </Card>
        </div>
    );

    const renderSettings = () => (
        <div className="space-y-6">
            <h2 className="text-xl font-bold">Mess Profile Settings</h2>
            <Card className="p-8">
                <form onSubmit={handleUpdateMess} className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="space-y-2">
                            <label className="text-sm font-bold text-gray-600">Mess Name</label>
                            <input
                                type="text"
                                value={messForm.name}
                                onChange={e => setMessForm({ ...messForm, name: e.target.value })}
                                className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all"
                                placeholder="Business Name"
                            />
                        </div>
                        <div className="space-y-2">
                            <label className="text-sm font-bold text-gray-600">Cuisine Types</label>
                            <input
                                type="text"
                                value={messForm.cuisine}
                                onChange={e => setMessForm({ ...messForm, cuisine: e.target.value })}
                                className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all"
                                placeholder="e.g. Maharashtrian, North Indian"
                            />
                        </div>
                        <div className="md:col-span-2 space-y-2">
                            <label className="text-sm font-bold text-gray-600">Description</label>
                            <textarea
                                rows={3}
                                value={messForm.description}
                                onChange={e => setMessForm({ ...messForm, description: e.target.value })}
                                className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all"
                                placeholder="Tell students about your kitchen and services..."
                            />
                        </div>
                        <div className="space-y-2">
                            <label className="text-sm font-bold text-gray-600">Address</label>
                            <div className="relative">
                                <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                                <input
                                    type="text"
                                    value={messForm.address}
                                    onChange={e => setMessForm({ ...messForm, address: e.target.value })}
                                    className="w-full pl-12 pr-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all"
                                    placeholder="Full location"
                                />
                            </div>
                        </div>
                        <div className="space-y-2">
                            <label className="text-sm font-bold text-gray-600">Contact Number</label>
                            <div className="relative">
                                <Phone className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                                <input
                                    type="text"
                                    value={messForm.contact}
                                    onChange={e => setMessForm({ ...messForm, contact: e.target.value })}
                                    className="w-full pl-12 pr-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all"
                                    placeholder="Business phone"
                                />
                            </div>
                        </div>
                    </div>

                    <div className="pt-6 border-t border-gray-100 flex justify-end">
                        <Button type="submit" isLoading={updating} className="rounded-xl px-12">
                            <Save size={18} className="mr-2" /> Save Changes
                        </Button>
                    </div>
                </form>
            </Card>
        </div>
    );

    return (
        <Layout>
            <div className="bg-dark text-white py-12 relative overflow-hidden">
                <div className="absolute inset-0 bg-primary opacity-5 animate-pulse" />
                <div className="container mx-auto px-4 relative">
                    <div className="flex flex-col md:row items-center justify-between gap-6">
                        <div className="space-y-2">
                            <h1 className="text-4xl font-heading font-black tracking-tighter">OWNER DASHBOARD</h1>
                            <div className="flex items-center space-x-2 text-primary">
                                <CircleCheck size={16} />
                                <p className="text-sm font-bold uppercase tracking-widest">{mess?.name || 'Loading...'}</p>
                            </div>
                        </div>
                        <div className="flex space-x-3">
                            <Button variant="outline" size="sm" className="rounded-xl border-white/20 text-white hover:bg-white/10 backdrop-blur-sm">
                                <ImageIcon size={18} className="mr-2" /> Manage Gallery
                            </Button>
                        </div>
                    </div>
                </div>
            </div>

            <div className="container mx-auto px-4 -mt-10 pb-20">
                <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
                    {/* Navigation */}
                    <div className="lg:col-span-1">
                        <Card className="p-2 space-y-1 sticky top-24 shadow-2xl shadow-primary/5 dark:bg-dark-card rounded-2xl">
                            {[
                                { id: 'overview', icon: <LayoutDashboard size={20} />, label: 'Overview' },
                                { id: 'menu', icon: <Utensils size={20} />, label: 'Menu Schedule' },
                                { id: 'subscribers', icon: <Users size={20} />, label: 'Subscribers' },
                                { id: 'settings', icon: <Settings size={20} />, label: 'Profile Settings' },
                            ].map((item) => (
                                <button
                                    key={item.id}
                                    onClick={() => setActiveTab(item.id as Tab)}
                                    className={`w-full flex items-center space-x-3 px-5 py-4 rounded-xl transition-all font-bold text-sm ${activeTab === item.id
                                        ? 'bg-primary text-white shadow-xl shadow-primary/30'
                                        : 'text-gray-500 hover:bg-gray-50'
                                        }`}
                                >
                                    {item.icon}
                                    <span>{item.label}</span>
                                </button>
                            ))}
                        </Card>
                    </div>

                    {/* Content Area */}
                    <div className="lg:col-span-3">
                        {loading ? (
                            <div className="space-y-6">
                                <div className="h-40 bg-gray-50 rounded-2xl animate-pulse" />
                                <div className="h-80 bg-gray-50 rounded-2xl animate-pulse" />
                            </div>
                        ) : (
                            <>
                                {activeTab === 'overview' && renderOverview()}
                                {activeTab === 'menu' && renderMenuManagement()}
                                {activeTab === 'subscribers' && renderSubscribers()}
                                {activeTab === 'settings' && renderSettings()}
                            </>
                        )}
                    </div>
                </div>
            </div>

            <BillingHistoryModal
                isOpen={isBillingModalOpen}
                onClose={() => setIsBillingModalOpen(false)}
            />
        </Layout>
    );
};

export default OwnerDashboardPage;

import React, { useState, useEffect, useCallback } from 'react';
import { Layout } from '../components/layout/Layout';
import { Card } from '../components/common/Card';
import { Button } from '../components/common/Button';
import {
    User, Mail, Phone, Calendar, Camera, ShieldCheck,
    Save, ArrowLeft, CircleCheck, Clock, Smartphone,
    LogOut, Trash2, Key, History, Edit3, UserCheck,
    Zap, ExternalLink
} from 'lucide-react';
import { useAppSelector, useAppDispatch } from '../../hooks/redux';
import type { RootState } from '../../store';
import Seo from '../components/common/Seo';
import { motion, AnimatePresence } from 'framer-motion';
import api, { getImageUrl } from '../api/axiosInstance';
import { updateAuthUser } from '../../store/slices/authSlice';
import type { Activity } from '../types/mess';
import { AxiosError } from 'axios';

type ActiveTab = 'personal' | 'security' | 'activity';

const ProfilePage: React.FC = () => {
    const { user } = useAppSelector((state: RootState) => state.auth);
    const dispatch = useAppDispatch();
    const [activeTab, setActiveTab] = useState<ActiveTab>('personal');
    const [isEditing, setIsEditing] = useState(false);
    const [formData, setFormData] = useState({
        name: user?.name || '',
        phone: user?.phone || '',
    });
    const [passwordData, setPasswordData] = useState({
        currentPassword: '',
        newPassword: '',
        confirmPassword: ''
    });
    const [activities, setActivities] = useState<Activity[]>([]);
    const [loadingActivities, setLoadingActivities] = useState(false);
    const [message, setMessage] = useState({ type: '', text: '' });

    const fetchProfile = useCallback(async () => {
        try {
            const response = await api.get('/users/profile');
            if (response.data.success) {
                const userData = response.data.user;
                dispatch(updateAuthUser(userData));
                setFormData({
                    name: userData.name || '',
                    phone: userData.phone || '',
                });
            }
        } catch (error) {
            console.error('Error fetching profile:', error);
        }
    }, [dispatch]);

    const fetchActivity = useCallback(async () => {
        setLoadingActivities(true);
        try {
            const response = await api.get('/users/activity');
            setActivities(response.data.data);
        } catch (error) { // Changed 'err' to 'error' for consistency and removed 'toast.error' as it's not imported
            console.error('Error fetching activity:', error);
        } finally {
            setLoadingActivities(false);
        }
    }, []);

    useEffect(() => {
        fetchProfile();
    }, [fetchProfile]);

    useEffect(() => {
        if (activeTab === 'activity') {
            fetchActivity();
        }
    }, [activeTab, fetchActivity]);

    const handleSave = async () => {
        try {
            const response = await api.put('/users/profile', formData);
            if (response.data.success) {
                dispatch(updateAuthUser(response.data.user));
                setMessage({ type: 'success', text: 'Profile updated successfully!' });
                setIsEditing(false);
            }
        } catch (error: any) {
            setMessage({ type: 'error', text: error.response?.data?.message || 'Update failed' });
        }
    };

    const handlePasswordChange = async () => {
        if (passwordData.newPassword !== passwordData.confirmPassword) {
            return setMessage({ type: 'error', text: 'Passwords do not match' });
        }
        try {
            await api.post('/users/change-password', passwordData);
            setMessage({ type: 'success', text: 'Password changed successfully!' });
            setPasswordData({ currentPassword: '', newPassword: '', confirmPassword: '' });
        } catch (err) {
            const error = err as AxiosError<{ message: string }>;
            setMessage({ type: 'error', text: error.response?.data?.message || 'Password change failed' });
        }
    };

    const triggerAvatarUpload = () => {
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = 'image/*';
        input.onchange = async (e: Event) => {
            const target = e.target as HTMLInputElement;
            const file = target.files?.[0];
            if (file) {
                const formData = new FormData();
                formData.append('avatar', file);
                try {
                    const response = await api.post('/users/upload-avatar', formData, {
                        headers: { 'Content-Type': 'multipart/form-data' }
                    });
                    if (response.data.success) {
                        const newAvatar = response.data.profile_image;
                        // Update profile with new image path
                        const updateRes = await api.put('/users/profile', {
                            name: user?.name,
                            phone: user?.phone,
                            profile_image: newAvatar
                        });
                        if (updateRes.data.success) {
                            dispatch(updateAuthUser(updateRes.data.user));
                            setMessage({ type: 'success', text: 'Avatar updated!' });
                        }
                    }
                } catch (err) {
                    setMessage({ type: 'error', text: 'Upload failed' });
                }
            }
        };
        input.click();
    };

    // Calculate profile completion
    const completionPercentage = (() => {
        let score = 0;
        if (user?.name) score += 25;
        if (user?.email) score += 25;
        if (user?.phone) score += 25;
        if (user?.profile_image) score += 25;
        return score;
    })();

    const joinDate = user?.created_at ? new Date(user.created_at).toLocaleDateString('en-US', {
        month: 'long',
        year: 'numeric'
    }) : 'March 2026';

    return (
        <Layout>
            <Seo
                title="Profile Discovery | MessWalha Dashboard"
                description="Manage your professional mess subscription profile"
            />

            <div className="min-h-screen bg-[#0f172a] relative overflow-hidden pt-32 pb-24">
                {/* Futuristic Background Elements */}
                <div className="absolute top-0 right-0 w-[800px] h-[800px] bg-primary-500/10 rounded-full blur-[150px] -mr-64 -mt-64 pointer-events-none" />
                <div className="absolute bottom-0 left-0 w-[600px] h-[600px] bg-indigo-500/10 rounded-full blur-[120px] -ml-64 -mb-64 pointer-events-none" />
                <div className="absolute inset-0 bg-[url('https://grainy-gradients.vercel.app/noise.svg')] opacity-20 pointer-events-none" />

                <div className="container mx-auto px-4 relative z-10">
                    {/* Header Breadcrumb */}
                    <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-12 gap-6">
                        <motion.button
                            initial={{ x: -20, opacity: 0 }}
                            animate={{ x: 0, opacity: 1 }}
                            onClick={() => window.history.back()}
                            className="flex items-center text-white/40 hover:text-primary-500 transition-all font-black uppercase tracking-[0.3em] text-[10px] group"
                        >
                            <ArrowLeft size={16} className="mr-3 group-hover:-translate-x-2 transition-transform" />
                            Discover Dashboard
                        </motion.button>

                        <AnimatePresence>
                            {message.text && (
                                <motion.div
                                    initial={{ y: -20, opacity: 0 }}
                                    animate={{ y: 0, opacity: 1 }}
                                    exit={{ y: -20, opacity: 0 }}
                                    className={`px-6 py-3 rounded-2xl border ${message.type === 'success' ? 'bg-green-500/10 border-green-500/20 text-green-500' : 'bg-red-500/10 border-red-500/20 text-red-500'} text-[10px] font-black uppercase tracking-widest`}
                                >
                                    {message.text}
                                </motion.div>
                            )}
                        </AnimatePresence>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
                        {/* Sidebar Column */}
                        <div className="lg:col-span-4 space-y-8">
                            <motion.div
                                initial={{ y: 30, opacity: 0 }}
                                animate={{ y: 0, opacity: 1 }}
                            >
                                <Card className="bg-white/5 backdrop-blur-3xl border-white/10 p-10 rounded-[3rem] shadow-3xl relative overflow-hidden text-center group">
                                    <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-primary-500 to-indigo-600" />

                                    <div className="relative inline-block mb-10">
                                        <div className="w-40 h-40 rounded-[2.5rem] bg-gradient-to-br from-primary-500 to-indigo-600 p-1 shadow-2xl shadow-primary-500/20">
                                            <div className="w-full h-full rounded-[2.3rem] overflow-hidden bg-dark-900 flex items-center justify-center">
                                                {user?.profile_image ? (
                                                    <img src={getImageUrl(user.profile_image)} alt={user.name} className="w-full h-full object-cover" />
                                                ) : (
                                                    <span className="text-6xl font-black text-white italic">{user?.name?.charAt(0)}</span>
                                                )}
                                            </div>
                                        </div>
                                        <motion.button
                                            whileHover={{ scale: 1.1 }}
                                            whileTap={{ scale: 0.9 }}
                                            onClick={triggerAvatarUpload}
                                            className="absolute bottom-0 right-0 p-4 bg-white dark:bg-dark-900 rounded-[1.5rem] shadow-2xl text-primary-500 hover:text-white hover:bg-primary-500 transition-all border border-white/10"
                                        >
                                            <Camera size={20} />
                                        </motion.button>
                                    </div>

                                    <div className="space-y-4">
                                        <div className="space-y-1">
                                            <h2 className="text-3xl font-black tracking-tighter text-white italic truncate">{user?.name}</h2>
                                            <p className="text-[10px] font-black uppercase tracking-[0.4em] text-primary-500">
                                                {user?.role === 'OWNER' ? 'Mess Partner' : 'User Account'}
                                            </p>
                                        </div>

                                        <div className="flex flex-col items-center gap-3 pt-6">
                                            <div className="flex items-center gap-2 px-4 py-2 bg-indigo-500/10 rounded-full border border-indigo-500/20">
                                                <UserCheck size={14} className="text-indigo-400" />
                                                <span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Verified User</span>
                                            </div>
                                            <div className="flex items-center gap-2 px-4 py-2 bg-primary-500/10 rounded-full border border-primary-500/20">
                                                <Zap size={14} className="text-primary-500" />
                                                <span className="text-[10px] font-black text-primary-500 uppercase tracking-widest">Active Subscription</span>
                                            </div>
                                        </div>

                                        <div className="pt-8 space-y-4 border-t border-white/5">
                                            <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest text-white/40">
                                                <span>Profile Completion</span>
                                                <span>{completionPercentage}%</span>
                                            </div>
                                            <div className="h-2 w-full bg-white/5 rounded-full overflow-hidden p-[2px]">
                                                <motion.div
                                                    initial={{ width: 0 }}
                                                    animate={{ width: `${completionPercentage}%` }}
                                                    className="h-full bg-gradient-to-r from-primary-500 to-indigo-600 rounded-full shadow-[0_0_15px_rgba(255,100,0,0.4)]"
                                                />
                                            </div>
                                        </div>

                                        <div className="flex items-center justify-between pt-6 text-[10px] font-black uppercase tracking-widest text-white/30">
                                            <span className="flex items-center gap-2"><Calendar size={12} /> Joined: {joinDate}</span>
                                            <span className="flex items-center gap-2"><Clock size={12} /> 12:45 PM</span>
                                        </div>
                                    </div>
                                </Card>
                            </motion.div>

                            <motion.div
                                initial={{ y: 30, opacity: 0 }}
                                animate={{ y: 0, opacity: 1 }}
                                transition={{ delay: 0.1 }}
                                className="space-y-2"
                            >
                                {[
                                    { id: 'personal', icon: User, label: 'Profile Information' },
                                    { id: 'security', icon: ShieldCheck, label: 'Security' },
                                    { id: 'activity', icon: History, label: 'Activity' }
                                ].map(tab => (
                                    <button
                                        key={tab.id}
                                        onClick={() => setActiveTab(tab.id as ActiveTab)}
                                        className={`w-full flex items-center justify-between px-8 py-5 rounded-[2rem] transition-all duration-500 font-black uppercase tracking-widest text-[10px] border ${activeTab === tab.id ? 'bg-primary-500 border-primary-400 text-white shadow-3xl shadow-primary-500/30' : 'bg-white/5 border-white/5 text-white/40 hover:bg-white/10 hover:text-white'}`}
                                    >
                                        <div className="flex items-center gap-4">
                                            <tab.icon size={18} />
                                            <span>{tab.label}</span>
                                        </div>
                                        <ArrowLeft size={16} className="rotate-180 opacity-40" />
                                    </button>
                                ))}
                            </motion.div>
                        </div>

                        {/* Main Content Column */}
                        <div className="lg:col-span-8">
                            <motion.div
                                key={activeTab}
                                initial={{ x: 20, opacity: 0 }}
                                animate={{ x: 0, opacity: 1 }}
                                transition={{ duration: 0.4 }}
                            >
                                <Card className="bg-white/5 backdrop-blur-3xl border-white/10 p-10 md:p-16 rounded-[3rem] shadow-3xl">
                                    <AnimatePresence mode="wait">
                                        {activeTab === 'personal' && (
                                            <motion.div
                                                key="personal-tab"
                                                initial={{ opacity: 0 }}
                                                animate={{ opacity: 1 }}
                                                exit={{ opacity: 0 }}
                                                className="space-y-12"
                                            >
                                                <div className="flex justify-between items-center">
                                                    <div>
                                                        <h3 className="text-4xl font-black text-white italic tracking-tighter">Profile <span className="text-primary-500">Information</span></h3>
                                                        <p className="text-[10px] font-black uppercase tracking-[0.3em] text-white/30 mt-2">View and update your profile details</p>
                                                    </div>
                                                    {!isEditing && (
                                                        <Button
                                                            variant="outline"
                                                            onClick={() => setIsEditing(true)}
                                                            className="rounded-full px-10 h-16 border-white/10 hover:bg-white/5 font-black uppercase tracking-widest text-[10px]"
                                                        >
                                                            <Edit3 size={18} className="mr-3" /> Edit Profile
                                                        </Button>
                                                    )}
                                                </div>

                                                <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-10">
                                                    {[
                                                        { label: 'Full Name', key: 'name', icon: User, placeholder: 'Enter Name' },
                                                        { label: 'Email Address', key: 'email', icon: Mail, disabled: true },
                                                        { label: 'Phone Number', key: 'phone', icon: Phone, placeholder: '+91 XXXXX XXXXX' },
                                                        { label: 'Join Date', key: 'joined', icon: Calendar, disabled: true, value: joinDate }
                                                    ].map((field) => (
                                                        <div key={field.key} className="space-y-4">
                                                            <label className="text-[10px] font-black uppercase tracking-[0.3em] text-white/30 ml-2">{field.label}</label>
                                                            <div className="relative group">
                                                                <div className="absolute left-6 top-1/2 -translate-y-1/2 text-primary-500 z-10">
                                                                    <field.icon size={18} />
                                                                </div>
                                                                <input
                                                                    type="text"
                                                                    disabled={field.disabled || !isEditing}
                                                                    value={field.value || (field.key === 'email' ? user?.email : (formData as Record<string, string>)[field.key])}
                                                                    onChange={e => setFormData({ ...formData, [field.key]: e.target.value })}
                                                                    placeholder={field.placeholder}
                                                                    className="w-full bg-white/[0.03] backdrop-blur-xl border border-white/10 rounded-[2rem] pl-16 pr-8 py-5 text-white font-black uppercase tracking-widest text-[10px] focus:ring-2 focus:ring-primary-500/40 focus:bg-white/[0.07] outline-none transition-all disabled:opacity-50 disabled:cursor-not-allowed group-hover:border-white/20"
                                                                />
                                                            </div>
                                                        </div>
                                                    ))}
                                                </div>

                                                {isEditing && (
                                                    <motion.div
                                                        initial={{ y: 20, opacity: 0 }}
                                                        animate={{ y: 0, opacity: 1 }}
                                                        className="flex flex-col sm:flex-row gap-4 pt-10 border-t border-white/5"
                                                    >
                                                        <button
                                                            onClick={handleSave}
                                                            className="flex-1 h-20 bg-gradient-to-r from-primary-500 to-primary-600 rounded-[2rem] text-white font-black uppercase tracking-[0.2em] text-xs shadow-2xl shadow-primary-500/40 hover:scale-[1.02] transition-all flex items-center justify-center gap-3 relative overflow-hidden group"
                                                        >
                                                            <div className="absolute inset-0 bg-white/20 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-1000" />
                                                            <Save size={20} /> Save Changes
                                                        </button>
                                                        <button
                                                            onClick={() => setIsEditing(false)}
                                                            className="flex-1 h-20 bg-white/5 border border-white/10 rounded-[2rem] text-white/50 font-black uppercase tracking-[0.2em] text-xs hover:text-white hover:bg-white/10 transition-all flex items-center justify-center gap-3"
                                                        >
                                                            Cancel
                                                        </button>
                                                    </motion.div>
                                                )}

                                                <div className="p-10 bg-indigo-500/5 rounded-[2.5rem] border border-indigo-500/10 space-y-4">
                                                    <div className="flex items-center gap-4 text-indigo-400">
                                                        <CircleCheck size={20} />
                                                        <span className="text-xs font-black uppercase tracking-widest italic">Compliance Status: Fully Aligned</span>
                                                    </div>
                                                    <p className="text-[10px] text-white/30 font-medium leading-relaxed italic">
                                                        Your data is encrypted using 256-bit AES protocols and stored across decentralized nodes for maximum privacy and resilience.
                                                    </p>
                                                </div>
                                            </motion.div>
                                        )}

                                        {activeTab === 'security' && (
                                            <motion.div
                                                key="security-tab"
                                                initial={{ opacity: 0 }}
                                                animate={{ opacity: 1 }}
                                                exit={{ opacity: 0 }}
                                                className="space-y-12"
                                            >
                                                <div className="space-y-2">
                                                    <h3 className="text-4xl font-black text-white italic tracking-tighter">Security <span className="text-primary-500">Fortress</span></h3>
                                                    <p className="text-[10px] font-black uppercase tracking-[0.3em] text-white/30">Protocol management and access control</p>
                                                </div>

                                                <div className="grid grid-cols-1 gap-10">
                                                    <div className="space-y-8 p-10 bg-white/5 rounded-[2.5rem] border border-white/5">
                                                        <div className="flex items-center gap-4">
                                                            <div className="w-12 h-12 rounded-2xl bg-primary-500/20 flex items-center justify-center text-primary-500">
                                                                <Key size={24} />
                                                            </div>
                                                            <h4 className="text-xl font-black text-white italic tracking-tight">Credential Rotation</h4>
                                                        </div>
                                                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                                            {[
                                                                { label: 'Current Key', key: 'currentPassword', type: 'password' },
                                                                { label: 'New Key', key: 'newPassword', type: 'password' },
                                                                { label: 'Confirm Key', key: 'confirmPassword', type: 'password' }
                                                            ].map(p => (
                                                                <div key={p.key} className="space-y-3">
                                                                    <label className="text-[9px] font-black uppercase text-white/30 ml-2 tracking-widest">{p.label}</label>
                                                                    <input
                                                                        type={p.type}
                                                                        value={(passwordData as Record<string, string>)[p.key]}
                                                                        onChange={e => setPasswordData({ ...passwordData, [p.key]: e.target.value })}
                                                                        className="w-full bg-dark-900 border border-white/10 rounded-2xl px-6 py-4 text-white text-xs font-black focus:ring-1 focus:ring-primary-500 outline-none transition-all"
                                                                        placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                                                                    />
                                                                </div>
                                                            ))}
                                                        </div>
                                                        <Button
                                                            onClick={handlePasswordChange}
                                                            className="w-full h-16 rounded-[1.5rem] bg-gradient-to-r from-primary-500 to-indigo-600 font-black uppercase tracking-widest text-[10px]"
                                                        >
                                                            Update Credential Protocol
                                                        </Button>
                                                    </div>

                                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                                        <div className="p-8 bg-white/5 rounded-[2.5rem] border border-white/5 space-y-6">
                                                            <div className="flex items-center justify-between">
                                                                <div className="flex items-center gap-4">
                                                                    <Smartphone size={24} className="text-indigo-400" />
                                                                    <h5 className="text-sm font-black text-white uppercase tracking-widest">2-Factor Auth</h5>
                                                                </div>
                                                                <div className="w-12 h-6 bg-white/10 rounded-full relative cursor-pointer">
                                                                    <div className="absolute left-1 top-1 w-4 h-4 bg-white/30 rounded-full" />
                                                                </div>
                                                            </div>
                                                            <p className="text-[10px] text-white/30 font-medium italic">Add an extra layer of defense to your account using biometric or SMS codes.</p>
                                                        </div>

                                                        <div className="p-8 bg-white/5 rounded-[2.5rem] border border-white/5 space-y-6">
                                                            <div className="flex items-center gap-4">
                                                                <LogOut size={24} className="text-white/40" />
                                                                <h5 className="text-sm font-black text-white uppercase tracking-widest">Active Sessions</h5>
                                                            </div>
                                                            <div className="flex items-center justify-between">
                                                                <span className="text-[10px] font-black text-white/30 italic">currently 1 active terminal</span>
                                                                <button className="text-[9px] font-black text-primary-500 uppercase tracking-widest">Wipe All</button>
                                                            </div>
                                                        </div>
                                                    </div>

                                                    <button className="flex items-center justify-center gap-3 p-8 border border-red-500/20 rounded-[2.5rem] hover:bg-red-500/5 transition-all text-red-500 group">
                                                        <Trash2 size={20} className="group-hover:rotate-12 transition-transform" />
                                                        <span className="text-[10px] font-black uppercase tracking-[0.3em]">Decommission Account Registry</span>
                                                    </button>
                                                </div>
                                            </motion.div>
                                        )}

                                        {activeTab === 'activity' && (
                                            <motion.div
                                                key="activity-tab"
                                                initial={{ opacity: 0 }}
                                                animate={{ opacity: 1 }}
                                                exit={{ opacity: 0 }}
                                                className="space-y-12"
                                            >
                                                <div className="flex justify-between items-center">
                                                    <div className="space-y-2">
                                                        <h3 className="text-4xl font-black text-white italic tracking-tighter">Activity <span className="text-primary-500">Chronicle</span></h3>
                                                        <p className="text-[10px] font-black uppercase tracking-[0.3em] text-white/30">Historical registry of your interactions</p>
