import { Input } from '../components/common/Input';
import { Card } from '../components/common/Card';
import { Utensils, User, Building } from 'lucide-react';
import { useAppDispatch } from '../../hooks/redux';
import { setCredentials } from '../../store/slices/authSlice';
import api from '../api/axiosInstance';
import { toast } from 'react-hot-toast';

const RegisterPage: React.FC = () => {
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        password: '',
        role: 'STUDENT' as 'STUDENT' | 'OWNER',
    });
    const [error, setError] = useState('');
    const [isLoading, setIsLoading] = useState(false);

    const dispatch = useAppDispatch();
    const navigate = useNavigate();

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        setError('');

        try {
            // Call backend directly for registration
            const response = await api.post('/auth/register', {
                name: formData.name,
                email: formData.email,
                phone: '', // Added empty phone to prevent backend SQL errors
                password: formData.password,
                role: formData.role
            });

            dispatch(setCredentials(response.data));
            navigate('/');
        } catch (error) {
            const err = error as any;
            toast.error(err.response?.data?.message || 'Registration failed');
            // The original setError was removed as per the instruction's implied change to use toast.error
            // The original console.error was also removed.
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-gray-50 dark:bg-dark px-4 py-12">
            <Card className="w-full max-w-2xl p-8">
