                        />
                        <Input
                            label="Password"
                            type="password"
                            placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó"
                            value={formData.password}
                            onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                            required
                            className="sm:col-span-2"
                        />
                    </div>

                    <p className="text-xs text-gray-500 text-center">
